const stringify=e=>("type"in e?stringifyToken:stringifyItem)(e);function stringifyToken(t){switch(t.type){case"block-scalar":{let e="";for(const o of t.props)e+=stringifyToken(o);return e+t.source}case"block-map":case"block-seq":{let e="";for(const n of t.items)e+=stringifyItem(n);return e}case"flow-collection":{let e=t.start.source;for(const r of t.items)e+=stringifyItem(r);for(const s of t.end)e+=s.source;return e}case"document":{let e=stringifyItem(t);if(t.end)for(const f of t.end)e+=f.source;return e}default:{let e=t.source;if("end"in t&&t.end)for(const i of t.end)e+=i.source;return e}}}function stringifyItem({start:e,key:t,sep:o,value:n}){let r="";for(const s of e)r+=s.source;if(t&&(r+=stringifyToken(t)),o)for(const f of o)r+=f.source;return n&&(r+=stringifyToken(n)),r}export{stringify};